style.script:
const CDN_BASE = "https://cdn.jsdelivr.net/gh/unknownsowner/htmlcode@main";
function game(name) {
  const url = `${CDN_BASE}/${name}.xml`;
  const win = window.open("about:blank", "_blank");
  fetch(url).then(r => r.text()).then(code => {
    win.document.open(); win.document.write(code); win.document.close();
  }).catch(() => win.document.write("Error loading game."));
}

const searchInput = document.getElementById("searchInput");
const allIcons = document.querySelectorAll(".icon");
searchInput.addEventListener("input", () => {
  const query = searchInput.value.toLowerCase();
  allIcons.forEach(icon => {
    const text = icon.querySelector(".icon-text").textContent.toLowerCase();
    icon.style.display = text.includes(query) ? "block" : "none";
  });
});
